#include <bits/stdc++.h>
using namespace std;
int n,m,f[1005],ans;
struct node
{
	int x,y,t;
} a[100005];
int fa(int u)
{
	if(f[u]==u) return u;
	return f[u]=fa(f[u]);
}
bool cmp(node a,node b)
{
	return a.t<b.t;
}
int main()
{
	cin>>n>>m;
	for(int i=1;i<=n;i++) f[i]=i;
	for(int i=1;i<=m;i++) cin>>a[i].x>>a[i].y>>a[i].t;
	sort(a+1,a+1+m,cmp);
	for(int i=1;i<=m;i++)
	{
		int fx=fa(a[i].x),fy=fa(a[i].y);
		if(fx!=fy)
		{
			f[fx]=fy;
			ans+=a[i].t;
			n--;
			if(n==1)
			{
				cout<<a[i].t;
				return 0;
			}
		}
	}
	cout<<-1;
	return 0;
}
